import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Users, LayoutDashboard, User, Home, LogOut } from 'lucide-react';

const Navbar = () => {
  const location = useLocation();
  const isLoggedIn = true; // Temporary mock

  const NavLink = ({ to, children, icon: Icon }) => {
    const isActive = location.pathname === to;
    return (
      <Link
        to={to}
        className={`flex items-center space-x-2 px-4 py-2 rounded-full transition-all duration-300 ${
          isActive 
            ? 'bg-primary-600 text-white shadow-lg' 
            : 'text-gray-400 hover:text-white hover:bg-white/5'
        }`}
      >
        <Icon size={18} />
        <span className="font-medium">{children}</span>
      </Link>
    );
  };

  return (
    <motion.nav 
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-50 px-6 py-4"
    >
      <div className="max-w-7xl mx-auto glass flex items-center justify-between px-8 py-3 rounded-full">
        <Link to="/" className="flex items-center space-x-2">
          <div className="w-10 h-10 bg-gradient-to-br from-primary-400 to-primary-700 rounded-xl flex items-center justify-center shadow-lg transform rotate-6 hover:rotate-0 transition-all duration-300">
            <span className="text-white font-bold text-xl">B</span>
          </div>
          <span className="text-2xl font-bold font-poppins tracking-tight">
            Buddy<span className="text-primary-400 font-extrabold uppercase text-sm ml-1">Up</span>
          </span>
        </Link>

        {isLoggedIn ? (
          <div className="hidden md:flex items-center space-x-2">
            <NavLink to="/" icon={Home}>Home</NavLink>
            <NavLink to="/find-buddies" icon={Users}>Find Buddies</NavLink>
            <NavLink to="/dashboard" icon={LayoutDashboard}>Dashboard</NavLink>
            <NavLink to="/profile" icon={User}>Profile</NavLink>
            <button className="flex items-center space-x-2 px-4 py-2 text-gray-400 hover:text-red-400 hover:bg-red-400/10 rounded-full transition-all duration-300">
              <LogOut size={18} />
              <span className="font-medium">Logout</span>
            </button>
          </div>
        ) : (
          <div className="flex items-center space-x-4">
            <Link to="/login" className="text-gray-400 hover:text-white transition-all">Login</Link>
            <Link to="/signup" className="btn-primary py-2 px-6">Join Now</Link>
          </div>
        )}
      </div>
    </motion.nav>
  );
};

export default Navbar;
